patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index d7afe2f426d3..4128e65ff7e2 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -2602,7 +2602,11 @@ bool VectorCombine::shrinkType(llvm::Instruction &I) {
   KnownBits KB = computeKnownBits(&I, *DL);
   if (KB.countMaxActiveBits() > BW)
     return false;
-
+  // For shift operations with non-constant shift amounts, do not shrink to avoid
+  // potential undefined behavior from truncated shift amounts.
+  if ((I.getOpcode() == Instruction::LShr || I.getOpcode() == Instruction::AShr ||
+       I.getOpcode() == Instruction::Shl) && !isa<Constant>(OtherOperand))
+    return false;
   // Calculate costs of leaving current IR as it is and moving ZExt operation
   // later, along with adding truncates if needed
   TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;

