diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index d7afe2f426d3..0614809f79ec 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -2602,6 +2602,42 @@ bool VectorCombine::shrinkType(llvm::Instruction &I) {
   KnownBits KB = computeKnownBits(&I, *DL);
   if (KB.countMaxActiveBits() > BW)
     return false;
+  // For shift operations, we need to ensure the shift amount is valid for the smaller type.
+  if (I.getOpcode() == Instruction::LShr || I.getOpcode() == Instruction::AShr || I.getOpcode() == Instruction::Shl) {
+    // If the other operand (shift amount) is not a constant, we cannot guarantee
+    // that the truncated shift amount will be less than the bit width of the
+    // smaller type. This could lead to undefined behavior/poison.
+    if (!isa<Constant>(OtherOperand))
+      return false;
+    
+    // For constant shift amounts, check if they are within bounds
+    unsigned ShiftAmtWidth = OtherOperand->getType()->getScalarSizeInBits();
+    if (ShiftAmtWidth <= BW) {
+      // The shift amount type is already small enough, but we still need to check values
+      if (auto *CI = dyn_cast<ConstantInt>(OtherOperand)) {
+        if (CI->getZExtValue() >= BW)
+          return false;
+      } else if (auto *CV = dyn_cast<ConstantVector>(OtherOperand)) {
+        for (unsigned i = 0; i < CV->getNumOperands(); ++i) {
+          if (auto *ElemCI = dyn_cast<ConstantInt>(CV->getOperand(i))) {
+            if (ElemCI->getZExtValue() >= BW)
+              return false;
+          } else {
+            // Non-constant element in vector - can't guarantee safety
+            return false;
+          }
+        }
+      } else if (!isa<ConstantAggregateZero>(OtherOperand)) {
+        // Other constant types that we can't analyze safely
+        return false;
+      }
+    }
+    // If ShiftAmtWidth > BW, truncation might make it safe, but we can't guarantee
+    // without knowing the actual values, so be conservative and don't transform
+    else {
+      return false;
+    }
+  }

